if (width >= 0 && height >= 0) {
    canvas.drawRect(0f, 0f, width.toFloat(), height.toFloat(), paint)
} else {
    canvas.drawPaint(paint)
}

if (options.allowRgb565 && config == Bitmap.Config.ARGB_8888 && outMimeType == MIME_TYPE_JPEG) {
    config = Bitmap.Config.RGB_565
}

if (SDK_INT >= 26 && outConfig == Bitmap.Config.RGBA_F16 && config != Bitmap.Config.HARDWARE) {
    config = Bitmap.Config.RGBA_F16
}

if (!preferExactIntrinsicSize && (startSize == -1 || endSize == -1)) {
    return -1
} else {
    return maxOf(startSize ?: -1, endSize ?: -1)
}

if (SDK_INT >= 26) {
    arrayOf(Bitmap.Config.ARGB_8888, Bitmap.Config.RGBA_F16)
} else {
    arrayOf(Bitmap.Config.ARGB_8888)
}

if (
    int32(bytes[0], bytes[1], bytes[2], bytes[3]) == 0x8950_4E47u &&
    int32(bytes[4], bytes[5], bytes[6], bytes[7]) == 0x0D0A_1A0Au
) {
    val width = int32(bytes[16], bytes[17], bytes[18], bytes[19])
    val height = int32(bytes[20], bytes[21], bytes[22], bytes[23])
    return width.toInt() to height.toInt()
}

when {
    movie.isOpaque && options.allowRgb565 -> Bitmap.Config.RGB_565
    options.bitmapConfig.isHardware -> Bitmap.Config.ARGB_8888
    else -> options.bitmapConfig
}

when {
    SDK_INT >= 26 && options.bitmapConfig == Bitmap.Config.HARDWARE -> Bitmap.Config.ARGB_8888
    else -> options.bitmapConfig
}

when (level) {
    Level.DEBUG -> Log.d(KOIN_TAG, msg)
    Level.INFO -> Log.i(KOIN_TAG, msg)
    Level.WARNING -> Log.w(KOIN_TAG, msg)
    Level.ERROR -> Log.e(KOIN_TAG, msg)
    else -> Log.e(KOIN_TAG, msg)
}

when {
    timeMillis <= 0 -> 0L
    timeMillis >= MAX_MS -> Long.MAX_VALUE
    else -> timeMillis * MS_TO_NS
}

when {
    a == null -> (arrayOfNulls<ThreadSafeHeapNode>(4) as Array<T?>).also { this.a = it }
    size >= a.size -> a.copyOf(size * 2).also { this.a = it }
    else -> a
}

while (i < len) {
    val h = hexToInt(s[i])
    val l = hexToInt(s[i + 1])
    require(!(h == -1 || l == -1)) { "Invalid hex chars: ${s[i]}${s[i + 1]}" }

    bytes[i / 2] = ((h shl 4) + l).toByte()
    i += 2
}

when (lexer.peekNextToken()) {
    TC_STRING -> readValue(isString = true)
    TC_OTHER -> readValue(isString = false)
    TC_BEGIN_OBJ -> readObject()
    TC_BEGIN_LIST -> readArray()
    else -> lexer.fail("Can't begin reading element, unexpected token")
}

if (modeReuseCache != null) {
    if (modeReuseCache[i] !== null || modeReuseCache[i] !== this)
        modeReuseCache[i] = this
}

if (Random.nextInt(0, size) == 0) {
    val iter = jsonToCache.iterator()
    while (iter.hasNext()) {
        if (iter.next().key.isDead) iter.remove()
    }
}

when (format) {
    ProtoIntegerType.FIXED -> out.writeInt(number.reverseBytes())
    ProtoIntegerType.DEFAULT -> encodeVarint64(number.toLong())
    ProtoIntegerType.SIGNED -> encodeVarint32(((number shl 1) xor (number shr 31)))
}

when {
    cls != DNS_CLASS_IN.toInt() -> source.skip(rdLength.toLong())
    type == DNS_TYPE_A.toInt() && rdLength == 4 -> addresses += readIpv4(source)
    type == DNS_TYPE_AAAA.toInt() && rdLength == 16 -> addresses += readIpv6(source)
    else -> source.skip(rdLength.toLong())
}

when {
    timeout == HttpTimeoutConfig.INFINITE_TIMEOUT_MS -> 0
    timeout < Int.MIN_VALUE -> Int.MIN_VALUE
    timeout > Int.MAX_VALUE -> Int.MAX_VALUE
    else -> timeout.toInt()
}

when (this) {
    CURL_HTTP_VERSION_1_0.toLong() -> HttpProtocolVersion.HTTP_1_0
    CURL_HTTP_VERSION_1_1.toLong() -> HttpProtocolVersion.HTTP_1_1
    CURL_HTTP_VERSION_2_0.toLong() -> HttpProtocolVersion.HTTP_2_0
    // old curl fallback
    else -> HttpProtocolVersion.HTTP_1_1
}

when {
    (flags and CURLWS_PING != 0) -> Frame.Ping(data)
    (flags and CURLWS_PONG != 0) -> Frame.Pong(data)
    (flags and CURLWS_CLOSE != 0) -> Frame.Close(data)
    else -> null
}

when (val version = response.version()) {
    HttpClient.Version.HTTP_1_1 -> HttpProtocolVersion.HTTP_1_1
    HttpClient.Version.HTTP_2 -> HttpProtocolVersion.HTTP_2_0
    else -> throw IllegalStateException("Unknown HTTP protocol version ${version.name}")
}

if (contentType != null) {
    contentType.charset() ?: Charsets.UTF_8
} else {
    Charsets.UTF_8
}

if (!isBody() || request.method == HttpMethod.Get || request.method == HttpMethod.Head) {
    logLines.add("--> END ${request.method.value}")
    return null
}

when (protocolVersion) {
    HttpProtocolVersion.HTTP_1_0 -> protocolVersion.toString()
    HttpProtocolVersion.HTTP_1_1 -> protocolVersion.toString()
    else -> null
}

when (postfix) {
    "?" -> TypeReference.Link.Optional(link)
    "+" -> TypeReference.Link.Array(link)
    else -> link
}

when {
    it == ' '.code.toByte() -> if (spaceToPlus) append('+') else append("%20")
    it in URL_ALPHABET || (!encodeFull && it in URL_PROTOCOL_PART) -> append(it.toInt().toChar())
    else -> append(it.percentEncode())
}
